import React, { useState } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  // Estado para saber si estamos logueados o no
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  // Estados para capturar lo que el usuario escribe
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');

  // Función para manejar el botón de entrar
  const handleLogin = async () => {
    try {
      // Enviamos los datos al servidor de Node.js (puerto 5000)
      const respuesta = await axios.post('http://localhost:5000/api/login', {
        usuario: usuario,
        clave: password // Mandamos la contraseña que escribió el usuario
      });

      if (respuesta.data.success) {
        setIsLoggedIn(true); // Si el servidor dice ok, entramos
      }
    } catch (error) {
      // Si el servidor responde error (401), mostramos el mensaje
      alert("Error: " + error.response.data.message);
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
  };
  // 1. SI NO ESTÁ LOGUEADO, MOSTRAR LOGIN
  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>Iniciar Sesión</h2>
          <div className="form-group">
            <label>Usuario:</label>
            <input 
              type="text" 
              placeholder="eduardo" 
              value={usuario}
              onChange={(e) => setUsuario(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label>Contraseña:</label>
            <input 
              type="password" 
              placeholder="••••••••••••" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          <button className="btn-entrar" onClick={handleLogin}>Entrar</button>
          <button className="btn-registrar">Registrarse</button>
        </div>
      </div>
    );
  }

  // 2. SI ESTÁ LOGUEADO, MOSTRAR DASHBOARD
  return (
    <div>
      <header className="header">
        <h1 style={{ margin: 0, fontSize: '24px' }}>Mi Tiendita - Dashboard</h1>
        <button className="btn-cerrar" onClick={handleLogout}>Cerrar Sesión</button>
      </header>

      <nav className="nav-bar">
        <span className="nav-link">Gestionar Productos</span>
        <span className="nav-link">Registrar Movimientos</span>
      </nav>

      <main className="dashboard-grid">
        <div className="card">
          <h3>Productos con Bajo Stock</h3>
          <div className="card-content">No hay productos con bajo stock.</div>
        </div>

        <div className="card">
          <h3>Productos Próximos a Caducar</h3>
          <div className="card-content">
            <strong>Leche Entera</strong> (Caduca: 2024-12-31)
          </div>
        </div>

        <div className="card">
          <h3>Resumen Diario de Movimientos</h3>
          <div className="card-content">No hay movimientos registrados hoy.</div>
        </div>

        <div className="card">
          <h3>Estadísticas Rápidas</h3>
          <div className="card-content">
            <p>Total de Productos: 0</p>
            <p>Valor Total del Inventario: 0</p>
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
